#include <stdio.h>
#include <stdlib.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int N,Q; scanf("%d %d",&N,&Q);
        int *arr = (int*)malloc((N+Q+5)*sizeof(int));
        int size=N;
        for(int i=0;i<N;i++) scanf("%d",&arr[i]);
        for(int i=0;i<Q;i++){
            int type; scanf("%d",&type);
            if(type==1){
                int P,V; scanf("%d %d",&P,&V);
                int idx=P-1;
                for(int j=size;j>idx;j--) arr[j]=arr[j-1];
                arr[idx]=V; size++;
            }else{
                int P; scanf("%d",&P);
                int idx=P-1;
                for(int j=idx;j<size-1;j++) arr[j]=arr[j+1];
                size--;
            }
        }
        for(int i=0;i<size;i++){
            if(i) printf(" ");
            printf("%d",arr[i]);
        }
        printf("\n");
        free(arr);
    }
    return 0;
}

