    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N,Q; cin>>N>>Q;
        vector<long long> a(N);
        for(int i=0;i<N;i++) cin>>a[i];
        for(int i=0;i<Q;i++){
            int type; cin>>type;
            if(type==1){
                int P; long long V; cin>>P>>V;
                a.insert(a.begin()+P-1, V);
            }else{
                int P; cin>>P;
                a.erase(a.begin()+P-1);
            }
        }
        for(size_t i=0;i<a.size();++i){
            if(i) cout<<' ';
            cout<<a[i];
        }
        cout<<'\n';
    }
    return 0;
}

