import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); Q = int(next(it))
        lst = [int(next(it)) for _ in range(N)]
        for __ in range(Q):
            typ = int(next(it))
            if typ == 1:
                P = int(next(it)); V = int(next(it))
                lst.insert(P-1, V)
            else:
                P = int(next(it))
                lst.pop(P-1)
        out_lines.append(' '.join(map(str, lst)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

